code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button } from 'decantr/components';

code.example:
function CtaBannerGradient() {
  const { section, h2, p } = tags;

  return section({ class: css('_py25 _px6 _text[center] _relative _z1'), style: 'background:linear-gradient(135deg,#F58882,#FDA303,#0AF3EB,#00E0AB)' },
    h2({ class: css('_fs[2.2rem] _fw700 _fgdark _mb3 _ls[-0.02em]') }, 'Ready to Build Something Great?'),
    p({ class: css('_fs[1.1rem] _fgdark/70 _mb8') }, 'Start building consistent, production-quality applications today.'),
    Button({ variant: 'dark', size: 'lg', class: css('_rounded[100px] _bgdark _fgwhite _fw700 _py3 _px9') }, 'Get Started')
  );
}

